tasks.starter:
# 1. automated syncPolicy 활성화
kubectl patch application guestbook -n argocd \
  --type=merge \
  -p '{
    "spec": {
      "syncPolicy": {
        "automated": {
          "selfHeal": ___,    # true: Git과 다른 변경 자동 복구
          "prune": ___         # true: Git에 없는 리소스 자동 삭제
        }
      }
    }
  }'

# 2. Drift 유발: guestbook-ui Deployment의 replicas를 직접 변경
kubectl scale deployment guestbook-ui -n guestbook --replicas=5

# 3. 즉시 상태 확인 (OutOfSync 되었다가 자동 복구)
kubectl get deployment guestbook-ui -n guestbook -w

# 4. ArgoCD가 감지한 drift 이력 확인
argocd app history guestbook
